ps.pstext:
if !IsFeatureImplemented(FEAT_SVE) && !IsFeatureImplemented(FEAT_SME) then
    EndOfDecode(Decode_UNDEF);
end;
let esize : integer{} = 8 << UInt(size);
let g : integer = UInt(Pg);
let dn : integer = UInt(Zdn);
let m : integer = UInt(Zm);
let a : integer = UInt(Za);
let sub_op : boolean = FALSE;

CheckSVEEnabled();
let VL : integer{} = CurrentVL();
let PL : integer{} = VL DIV 8;
let elements : integer = VL DIV esize;
let mask : bits(PL) = P{}(g);
let operand1 : bits(VL) = Z{}(dn);
let operand2 : bits(VL) = if AnyActiveElement{PL}(mask, esize) then Z{VL}(m) else Zeros{VL};
let operand3 : bits(VL) = if AnyActiveElement{PL}(mask, esize) then Z{VL}(a) else Zeros{VL};
var result : bits(VL);

for e = 0 to elements-1 do
    if ActivePredicateElement{PL}(mask, e, esize) then
        let element1 : integer = UInt(operand1[e*:esize]);
        let element2 : integer = UInt(operand2[e*:esize]);
        let product : integer = element1 * element2;
        if sub_op then
            result[e*:esize] = operand3[e*:esize] - product;
        else
            result[e*:esize] = operand3[e*:esize] + product;
        end;
    else
        result[e*:esize] = operand1[e*:esize];
    end;
end;

Z{VL}(dn) = result;
